create table if not exists public.membership_applications (id uuid primary key default gen_random_uuid(),full_name text not null,dob text,email text not null,phone text,address text,rejoining text,last_membership_date text,committee_members text,visit_date text,agree_to_fees boolean default false,agree_to_annual_fee boolean default false,agree_to_gdpr boolean default false,signature text,proposer_name text,seconder_name text,received_date date,approved_date date,membership_number text,signed_by text,committee_signature text,status text default 'pending',created_at timestamptz default now());alter table public.membership_applications enable row level security;create policy "membership_applications insert public" on public.membership_applications for insert with check (true);create policy "membership_applications admin read" on public.membership_applications for select using (public.is_admin());create policy "membership_applications admin update" on public.membership_applications for update using (public.is_admin()) with check (public.is_admin());
